patch:
--- linux-2.6.6.orig/init/main.c	2004-05-14 13:38:31.000000000 +0800
+++ linux-2.6.6/init/main.c	2004-05-14 15:16:55.888691104 +0800
@@ -242,9 +242,17 @@ __setup("quiet", quiet_kernel);
    failed parameters */
 static int __init unknown_bootoption(char *param, char *val)
 {
-	/* Change NUL term back to "=", to make "param" the whole string. */
-	if (val)
-		val[-1] = '=';
+	/* Change NUL term back to "=" and restore quotes, to make "param"
+	   the whole string. */
+	if (val) {
+		if (val[-1] == '"') {
+			val[-2] = '=';
+			val[strlen(val)] = '"';
+			val[strlen(val) + 1] = '\0';
+		}
+		else
+			val[-1] = '=';
+	}

 	/* Handle obsolete-style parameters */
 	if (obsolete_checksetup(param))
